def predict(triples: List[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Group triples by subject to handle different entities properly
    subject_triples: Dict[str, List[Triple]] = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Find the main subject (the monument, not the country/location)
    main_subject = None
    for sub in subject_triples.keys():
        if "Monument" in sub or "Memorial" in sub or "Plack" in sub or "Battlefield" in sub:
            main_subject = sub
            break

    # Fallback to first subject if no monument found
    if main_subject is None:
        main_subject = list(subject_triples.keys())[0]

    main_triples = subject_triples.get(main_subject, [])
    other_subjects = [sub for sub in subject_triples.keys() if sub != main_subject]

    def get_phrase(triple: Triple, is_main: bool = True) -> str:
        p = triple.predicate
        o = triple.object.strip('"')  # remove surrounding quotes if present

        # Map predicates to natural‑language fragments
        if p == "category":
            return f"which is categorized as {o}"
        elif p == "country":
            return f"located in the country of {o}"
        elif p == "location":
            return f"located in {o}"
        elif p == "municipality":
            return f"in the municipality of {o}"
        elif p == "state":
            return f"in the state of {o}"
        elif p == "district":
            return f"in the district of {o}"
        elif p in ("established", "foundingDate"):
            return f"established on {o}"
        elif p in ("owner", "owningOrganisation"):
            return f"owned by {o}"
        elif p == "inaugurationDate":
            return f"inaugurated on {o}"
        elif p == "capital":
            return f"whose capital is {o}"
        elif p == "legislature":
            return f"with legislature {o}"
        elif p == "dedicatedTo":
            return f"dedicated to {o}"
        elif p == "designer":
            return f"designed by {o}"
        elif p == "material":
            return f"made of {o}"
        elif p == "ethnicGroup":
            return f"with ethnic group {o}"
        elif p == "language":
            return f"where {o} is spoken"
        elif p == "religion":
            return f"following {o}"
        elif p == "nearestCity":
            return f"nearest to {o}"
        elif p == "currency":
            return f"using {o}"
        elif p == "largestCity":
            return f"whose largest city is {o}"
        elif p == "leader":
            return f"led by {o}"
        elif p == "leaderTitle":
            return f"with leader title {o}"
        elif p.startswith("hasToIts"):
            direction = p.replace("hasToIts", "").lower()
            return f"to its {direction} lies {o}"
        elif p == "nativeName":
            return f'known as "{o}" in its native language'
        else:
            # Fallback for any unexpected predicate
            return f"{o}"

    # Build main subject phrases
    main_phrases = []
    for triple in main_triples:
        main_phrases.append(get_phrase(triple, True))

    # Build related subject phrases (country info, etc.)
    related_phrases = []
    for sub in other_subjects:
        for triple in subject_triples[sub]:
            related_phrases.append(get_phrase(triple, False))

    # Build the sentence with better structure
    if main_phrases:
        # Start with the main subject and its first phrase
        sentence = f"{main_subject}"

        # Add main phrases with appropriate connectors
        if len(main_phrases) == 1:
            sentence += f" {main_phrases[0]}"
        else:
            # First phrase directly, rest with commas
            sentence += f" {main_phrases[0]}"
            for phrase in main_phrases[1:]:
                sentence += f", {phrase}"

        # Add related information as relative clauses
        if related_phrases:
            # Use "which" for additional entity information
            sentence += ", which"
            sentence += " " + ", and ".join(related_phrases)
    else:
        sentence = main_subject

    sentence += "."
    return sentence

